const bySheet = new Map();
for (const item of cases) {
  if (!bySheet.has(item.sheet)) {
    bySheet.set(item.sheet, []);
  }
  bySheet.get(item.sheet).push(item.row);
}

const workbook = Workbook.create();
const summary = workbook.worksheets.add("Summary");

const priorityFill = {
  Critical: "#C00000",
  High: "#E26B0A",
  Medium: "#FFC000",
  Low: "#92D050",
};

const severityFill = {
  Critical: "#7F0000",
  Major: "#C0504D",
  Minor: "#F4B183",
  Trivial: "#D9EAD3",
};

function toColumnName(index) {
  let n = index + 1;
  let name = "";
  while (n > 0) {
    const rem = (n - 1) % 26;
    name = String.fromCharCode(65 + rem) + name;
    n = Math.floor((n - 1) / 26);
  }
  return name;
}

function sanitizeTableName(name) {
  return name.replace(/[^A-Za-z0-9]/g, "").slice(0, 20) || "Sheet";
}

function applyHeader(sheet, lastCol, rowCount) {
  sheet.freezePanes.freezeRows(1);
  sheet.showGridLines = false;
  sheet.getRange(`A1:${lastCol}1`).format = {
    fill: "#1F4E78",
    font: { bold: true, color: "#FFFFFF" },
    wrapText: true,
  };
  sheet.getRange(`A1:${lastCol}${rowCount}`).format = {
    wrapText: true,
  };
}

function applyWidths(sheet) {
  const widths = [18,14,14,10,10,22,28,28,30,16,10,40,26,26,26,28,28,28,28,36,18,22,20,18,12,22];
  widths.forEach((width, idx) => {
    const col = toColumnName(idx);
    sheet.getRange(`${col}:${col}`).format.columnWidth = width;
  });
}

for (const [sheetName, rows] of bySheet.entries()) {
  const sheet = workbook.worksheets.add(sheetName);
  const values = [columns, ...rows];
  const lastCol = toColumnName(columns.length - 1);
  sheet.getRange(`A1:${lastCol}${values.length}`).values = values;
  applyHeader(sheet, lastCol, values.length);
  applyWidths(sheet);

  for (let i = 0; i < rows.length; i += 1) {
    const excelRow = i + 2;
    const priority = rows[i][3];
    const severity = rows[i][4];
    sheet.getRange(`D${excelRow}`).format = { fill: priorityFill[priority] ?? "#D9E2F3", font: { color: "#FFFFFF", bold: true } };
    sheet.getRange(`E${excelRow}`).format = { fill: severityFill[severity] ?? "#D9E2F3", font: { color: "#FFFFFF", bold: true } };
    sheet.getRange(`Y${excelRow}`).values = [["Not Run"]];
  }

  sheet.tables.add(`A1:${lastCol}${values.length}`, true, `${sanitizeTableName(sheetName)}Table`);
}

const sheetOrder = [
  "Authentication","User Management","Product","Category","Cart","Checkout","Order","Payment","Shipping",
  "Inventory","Notification","Dashboard/Admin","Role & Permission","API Validation","Security","Performance",
  "Edge Cases","Regression Critical","DB Validation","Integration","Error Handling","Logging/Audit",
  "Background Job/Webhook","Search/Filter/Sort","File Upload","Responsive/UI Validation",
  "Banner","Supplier","Voucher","POS","Recommendation"
];

const summaryRows = sheetOrder
  .filter((name) => bySheet.has(name))
  .map((name) => {
    const moduleCases = bySheet.get(name).length;
    const critical = bySheet.get(name).filter((r) => r[3] === "Critical").length;
    const high = bySheet.get(name).filter((r) => r[3] === "High").length;
    return [name, moduleCases, critical, high, "Source-backed from controllers/services/DbContext/docs"];
  });

const totalCases = cases.length;
const totalCritical = cases.filter((x) => x.row[3] === "Critical").length;
const totalHigh = cases.filter((x) => x.row[3] === "High").length;

summary.getRange("A1:E1").merge();
summary.getRange("A1").values = [[
  "Tech_Store Enterprise Test Case & User Story Workbook"
]];
summary.getRange("A1:E1").format = {
  fill: "#0F243E",
  font: { color: "#FFFFFF", bold: true },
};

summary.getRange("A3:D6").values = [
  ["Metric", "Value", "Coverage Target", "Source of Truth"],
  ["Total Test Cases", totalCases, "100% critical business flow", "Controllers + Services + DbContext + Markdown"],
  ["Critical Priority", totalCritical, ">= all revenue/security/admin critical flows", "Checkout/Auth/Order/Payment/Permission"],
  ["High Priority", totalHigh, ">= 90% API and DB integrity coverage", "APIs, settings, inventory, notifications"],
];
summary.getRange("A3:D6").format = { wrapText: true };
summary.getRange("A3:D3").format = { fill: "#1F4E78", font: { color: "#FFFFFF", bold: true } };

summary.getRange(`A9:E${8 + summaryRows.length + 1}`).values = [
  ["Module", "Test Case Count", "Critical Count", "High Count", "Remarks"],
  ...summaryRows,
];
summary.getRange("A9:E9").format = { fill: "#1F4E78", font: { color: "#FFFFFF", bold: true } };
summary.freezePanes.freezeRows(9);
summary.showGridLines = false;
summary.tables.add(`A9:E${9 + summaryRows.length}`, true, "SummaryCounts");

summary.getRange("G3:J8").values = [
  ["Analysis Inputs", "Value", "Implementation Note", "QA Use"],
  ["Storefront Controllers", 8, "Authentication, Home, User, Payment, Banner, Recommendation, Notifications, Interaction", "Regression + UAT"],
  ["Admin Controllers", 17, "Product, Order, Stock, POS, Supplier, Voucher, Banner, Settings, Users, etc.", "Manual + permission"],
  ["Middleware", 4, "Guest cookie, request tracking, product tracking, admin auth helper", "Security + audit"],
  ["Background/Webhook Flows", 4, "Event queue, merge session, retention cleanup, SePay IPN placeholder", "Ops + integration"],
  ["API Contract Source", "obj/Debug/net8.0/ApiEndpoints.json", "No Swagger/OpenAPI file present", "Automation baseline"],
];
summary.getRange("G3:J3").format = { fill: "#1F4E78", font: { color: "#FFFFFF", bold: true } };

const chart = summary.charts.add("bar", summary.getRange(`A9:B${9 + summaryRows.length}`));
chart.title = "Test Cases by Module";
chart.hasLegend = false;
chart.xAxis = { axisType: "textAxis" };
chart.setPosition("G10", "N28");

["A:A","B:B","C:C","D:D","E:E","G:G","H:H","I:I","J:J"].forEach((range) => {
  summary.getRange(range).format.columnWidth = 24;
});

await fs.mkdir(desktopDir, { recursive: true });
const renderedSheets = ["Summary", "Authentication", "Payment", "Inventory", "Dashboard/Admin"];
for (const sheetName of renderedSheets) {
  await workbook.render({ sheetName, autoCrop: "all", scale: 1, format: "png" });
}

const file = await SpreadsheetFile.exportXlsx(workbook);
await file.save(outputPath);

